import { join } from "node:path";
import type { GeneratedFile } from "./codeGenerationRunner.js";

const EXPECTED_DIR_NAME = "__expected__";
const TYPE_ERRORS_FILENAME = "type-errors.txt";
const SCHEMA_FILENAME = "schema.graphql";
const QUERY_RESULT_FILENAME = "query-result.json";

export interface SnapshotFile {
  content: string;
  expectedPath: string;
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

/**
 * Replaces the plugin version embedded in the `@generated by <plugin> vX.Y.Z`
 * header with a fixed placeholder so golden snapshots stay stable across
 * releases. Without this, every version bump (changesets' "Version Packages")
 * would change the header and break the snapshot tests right after a release.
 *
 * The plugin name is injected so this works for any `createEcmaScriptPlugin`
 * based plugin (which all emit the same header format). Prerelease tags (e.g.
 * `0.8.0-next-...`) are also covered.
 */
export function normalizePluginVersion(
  content: string,
  pluginName: string,
): string {
  const pattern = new RegExp(
    `(@generated by ${escapeRegExp(pluginName)} )v\\d+\\.\\d+\\.\\d+(?:-[0-9A-Za-z.-]+)?`,
    "g",
  );
  return content.replace(pattern, "$1vX.Y.Z");
}

/**
 * Gets the __expected__ directory path for a test case.
 */
export function getExpectedDirPath(testCaseDir: string): string {
  return join(testCaseDir, EXPECTED_DIR_NAME);
}

/**
 * Gets the expected type-errors.txt path for a test case.
 */
export function getExpectedTypeErrorsPath(testCaseDir: string): string {
  return join(testCaseDir, EXPECTED_DIR_NAME, TYPE_ERRORS_FILENAME);
}

/**
 * Gets the expected schema.graphql path for a test case.
 */
export function getExpectedSchemaPath(testCaseDir: string): string {
  return join(testCaseDir, EXPECTED_DIR_NAME, SCHEMA_FILENAME);
}

/**
 * Gets the expected query-result.json path for a test case.
 */
export function getExpectedQueryResultPath(testCaseDir: string): string {
  return join(testCaseDir, EXPECTED_DIR_NAME, QUERY_RESULT_FILENAME);
}

/**
 * Collects generated files and maps them to their expected snapshot paths.
 * Each generated file is mapped to the corresponding path under __expected__/,
 * with the plugin version normalized so snapshots stay release-stable.
 *
 * @param testCaseDir - The test case directory path
 * @param generatedFiles - Array of generated files with name and content
 * @param options - Snapshot options; `pluginName` identifies the generator
 *   whose version header should be normalized
 * @returns Array of snapshot files with content and expected paths
 */
export async function collectGeneratedFilesForSnapshot(
  testCaseDir: string,
  generatedFiles: GeneratedFile[],
  options: { pluginName: string },
): Promise<SnapshotFile[]> {
  const expectedDir = getExpectedDirPath(testCaseDir);

  return generatedFiles.map((file) => ({
    content: normalizePluginVersion(file.content, options.pluginName),
    expectedPath: join(expectedDir, file.name),
  }));
}
